import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as s,c as n,a2 as d}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Додавання каналу Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/google-drive.md","filePath":"uk-UA/upload/google-drive.md","lastUpdated":1781962217000}'),r={name:"uk-UA/upload/google-drive.md"};function c(p,e,h,g,u,b){return s(),n("div",null,[...e[0]||(e[0]=[d('<h1 id="додавання-каналу-google-drive" tabindex="-1">Додавання каналу Google Drive <a class="header-anchor" href="#додавання-каналу-google-drive" aria-label="Permalink to &quot;Додавання каналу Google Drive&quot;">​</a></h1><h2 id="що-підготувати-спочатку" tabindex="-1">Що підготувати спочатку <a class="header-anchor" href="#що-підготувати-спочатку" aria-label="Permalink to &quot;Що підготувати спочатку&quot;">​</a></h2><p>Перед початком підготуйте:</p><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис Google</td><td>Для доступу до Google Cloud і авторизації Google Drive</td></tr><tr><td>Проєкт Google Cloud</td><td>Для ввімкнення Drive API і створення OAuth credentials</td></tr><tr><td>OAuth 2.0 client</td><td>ImgBed використовує його для отримання <code>Client ID</code>, <code>Client Secret</code> і <code>Refresh Token</code></td></tr><tr><td>Ваш домен ImgBed</td><td>Для OAuth redirect URI. Він має збігатися з доменом, який ви реально використовуєте.</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="крок-1-увімкніть-google-drive-api" tabindex="-1">Крок 1. Увімкніть Google Drive API <a class="header-anchor" href="#крок-1-увімкніть-google-drive-api" aria-label="Permalink to &quot;Крок 1. Увімкніть Google Drive API&quot;">​</a></h3><ol><li>Відкрийте Google Cloud Console.</li><li>Створіть новий проєкт або виберіть наявний.</li><li>Перейдіть до <code>APIs &amp; Services</code>.</li><li>Натисніть <code>Enable APIs and Services</code>.</li><li>Знайдіть <code>Google Drive API</code>.</li><li>Відкрийте його й натисніть enable.</li></ol><h3 id="крок-2-налаштуите-oauth-consent-screen" tabindex="-1">Крок 2. Налаштуйте OAuth Consent Screen <a class="header-anchor" href="#крок-2-налаштуите-oauth-consent-screen" aria-label="Permalink to &quot;Крок 2. Налаштуйте OAuth Consent Screen&quot;">​</a></h3><ol><li>У Google Cloud відкрийте <code>Google Auth Platform</code>.</li><li>Заповніть базову інформацію <code>Branding</code>: назву app, support email і developer contact email.</li><li>Відкрийте <code>Audience</code>.</li><li>Для більшості особистих self-hosted розгортань виберіть <code>External</code>.</li><li>Якщо вибрали <code>External</code>, додайте Google-акаунт, який хочете авторизувати, у <code>Test users</code>.</li><li>Відкрийте <code>Data Access</code>.</li><li>Додайте потрібні permissions для Google Drive.</li></ol><h3 id="крок-3-створіть-oauth-2-0-client" tabindex="-1">Крок 3. Створіть OAuth 2.0 Client <a class="header-anchor" href="#крок-3-створіть-oauth-2-0-client" aria-label="Permalink to &quot;Крок 3. Створіть OAuth 2.0 Client&quot;">​</a></h3><ol><li>У <code>Google Auth Platform</code> відкрийте <code>Clients</code>.</li><li>Створіть новий client.</li><li>Встановіть application type як <code>Web application</code>.</li><li>Дайте client зрозумілу назву.</li><li>Для authorized JavaScript origins введіть URL вашого ImgBed, наприклад:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Для authorized redirect URIs введіть:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Створення OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="Введення домену та callback URL" loading="lazy"></p><p>Після створення client скопіюйте ці значення:</p><table tabindex="0"><thead><tr><th>Згенероване значення</th><th>Поле ImgBed</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="крок-4-заповніть-канал-google-drive" tabindex="-1">Крок 4. Заповніть канал Google Drive <a class="header-anchor" href="#крок-4-заповніть-канал-google-drive" aria-label="Permalink to &quot;Крок 4. Заповніть канал Google Drive&quot;">​</a></h2><p>У налаштуваннях завантаження виберіть <code>Google Drive</code> і заповніть:</p><table tabindex="0"><thead><tr><th>Поле ImgBed</th><th>Що ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Зрозуміла назва, наприклад <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID з Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret з Google Cloud</td></tr><tr><td>Refresh Token</td><td>Поки залиште порожнім. Отримайте його на наступному кроці.</td></tr><tr><td>Root directory</td><td>Необов&#39;язково. Типово <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Вставлення client details в ImgBed" loading="lazy"></p><h2 id="крок-5-отримаите-refresh-token" tabindex="-1">Крок 5. Отримайте Refresh Token <a class="header-anchor" href="#крок-5-отримаите-refresh-token" aria-label="Permalink to &quot;Крок 5. Отримайте Refresh Token&quot;">​</a></h2><ol><li>Натисніть <code>Get Token</code>.</li><li>Виберіть Google-акаунт, який хочете підключити.</li><li>Пройдіть підказки авторизації.</li><li>На callback-сторінці з&#39;явиться <code>Refresh Token</code>.</li><li>Скопіюйте його.</li><li>Поверніться до ImgBed і вставте його в поле <code>Refresh Token</code>.</li></ol><p><img src="'+l+`" alt="Копіювання Refresh Token після авторизації" loading="lazy"></p><p>Якщо пізніше зміните Google-акаунт, OAuth client або стара авторизація завершиться, канал видаляти не потрібно. Відкрийте сторінку редагування й натисніть <code>Reauthorize</code>.</p><h2 id="крок-6-збережіть-канал" tabindex="-1">Крок 6. Збережіть канал <a class="header-anchor" href="#крок-6-збережіть-канал" aria-label="Permalink to &quot;Крок 6. Збережіть канал&quot;">​</a></h2><p>Коли всі поля заповнені, збережіть канал.</p><h2 id="короткии-сценаріи" tabindex="-1">Короткий сценарій <a class="header-anchor" href="#короткии-сценаріи" aria-label="Permalink to &quot;Короткий сценарій&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Відкрити Google Cloud</span></span>
<span class="line"><span>-&gt; Створити або вибрати проєкт</span></span>
<span class="line"><span>-&gt; Увімкнути Google Drive API</span></span>
<span class="line"><span>-&gt; Налаштувати Google Auth Platform</span></span>
<span class="line"><span>-&gt; Якщо Audience = External, додати свій Google-акаунт у Test users</span></span>
<span class="line"><span>-&gt; Створити Web application OAuth client</span></span>
<span class="line"><span>-&gt; Використати https://your-domain.com/api/oauth/google/callback як redirect URI</span></span>
<span class="line"><span>-&gt; Ввести Client ID і Client Secret в ImgBed</span></span>
<span class="line"><span>-&gt; Натиснути Get Token</span></span>
<span class="line"><span>-&gt; Увійти через Google і авторизувати</span></span>
<span class="line"><span>-&gt; Скопіювати Refresh Token з callback-сторінки</span></span>
<span class="line"><span>-&gt; Вставити його назад в ImgBed і зберегти</span></span>
<span class="line"><span>-&gt; Завантажити тестове зображення</span></span></code></pre></div><h2 id="посилання" tabindex="-1">Посилання <a class="header-anchor" href="#посилання" aria-label="Permalink to &quot;Посилання&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const f=i(r,[["render",c]]);export{k as __pageData,f as default};
